18	  steps: Step[];
19	};
20	
21	type ScenarioOutput = {
22	  results: unknown[];
23	};
24	
25	const PROCESSING_FEE = 5;
26	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
27	const COMPONENT_BLOCK_SIZE = 3;
28	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
29	
30	const BASE_PREMIUMS: Record<string, number> = {
31	  sword: 100,
32	  amulet: 60,
33	  staff: 80,
34	  potion: 40,
35	  rune: 25,
36	  moonstone: 25,
37	};
38	
39	const isBlockOfAlikeItems = (items: Item[]): boolean =>
40	  items.length === COMPONENT_BLOCK_SIZE &&
41	  items.every((item) => item.type === items[0].type);
42	
43	const basePremiumFor = (items: Item[]): number =>
44	  isBlockOfAlikeItems(items)
45	    ? COMPONENT_BLOCK_BASE_PREMIUM
46	    : items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
47	
48	const quotePremium = (items: Item[]): number => {
49	  const basePremium = basePremiumFor(items);
50	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
51	  return Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
52	};
53	
54	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
55	  const items = input.steps[0].items ?? [];
56	  return { results: [{ premium: quotePremium(items) }] };
57	};
