const basePremiumFor = (items: Item[]): number => {
  const countsByType = new Map<string, number>();
  for (const item of items) {
    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
  }

  let basePremium = 0;
  for (const [type, count] of countsByType) {
    basePremium +=
      count === COMPONENT_BLOCK_SIZE
        ? COMPONENT_BLOCK_BASE_PREMIUM
        : count * BASE_PREMIUMS[type];
  }
  return basePremium;
};
